module dynamic_range_compressor(  
    input signed [4:0] in_signal,  
    output signed [4:0] out_signal  
);  
    wire inv_out_signal = (in_signal < -2) ? -2 :  
                        (in_signal > 2) ? 2 :  
                        in_signal;
    assign out_signal = inv_out_signal;  
endmodule
